-- Ashton Vale — case_answers data migration (extracted from data/songs/*.js)
--
-- This table stores the real accepted answers for all 600 cases' 7 fields
-- (location, object, witness, time, marker, direction, sound), already
-- normalized (lowercase, trimmed, whitespace-collapsed) the same way
-- case.html's existing norm() function does it.
--
-- NOTHING reads this table yet -- case.html still checks answers entirely
-- client-side, unchanged. This migration only stores the data server-side
-- so a future Edge Function can validate against it. RLS is enabled with
-- zero policies, so no anon or authenticated request can read a single
-- row via the API, same lockdown as puzzle_answers.

create table if not exists case_answers (
  id uuid primary key default gen_random_uuid(),
  case_id text not null,
  field_id text not null,
  accepted_answers jsonb not null default '[]',
  unique (case_id, field_id)
);

alter table case_answers enable row level security;
revoke all on case_answers from anon, authenticated; -- default-deny, no policies at all

-- Superseded by case_answers (puzzle_answers assumed one hash per case,
-- which can't represent 7 fields with fuzzy/substring matching). Drop it
-- if it was created by an earlier version of this migration.
drop table if exists puzzle_answers;

-- Bulk load all 4200 rows (600 cases x 7 fields) in one statement.
insert into case_answers (case_id, field_id, accepted_answers)
select case_id, field_id, accepted_answers
